package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.*;

/**
 * Selects a minimal set of test cases that covers all failing implementations,
 * using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Returns a minimal set of test cases that covers all failing implementations
     * using a greedy set cover algorithm. Does not mutate the input TestResults.
     *
     * @param results the test results containing test cases and coverage info
     * @return a set of test cases that covers all failing files
     */
    public static Set<TestCase> setCover(TestResults results) {
        // Make internal copies to avoid mutating input
        Set<Integer> uncovered = new HashSet<>(results.getWrongSet());
        List<Set<Integer>> caseToFiles = new ArrayList<>();
        for (Set<Integer> fileSet : results.getCaseToFiles()) {
            caseToFiles.add(new HashSet<>(fileSet));
        }

        Set<TestCase> cover = new HashSet<>();

        // Greedy set cover: repeatedly pick the test case covering the most uncovered files
        while (!uncovered.isEmpty()) {
            int bestIdx = -1;
            int bestCount = 0;

            for (int i = 0; i < caseToFiles.size(); i++) {
                // Count how many uncovered files this test case covers
                int count = 0;
                for (Integer file : caseToFiles.get(i)) {
                    if (uncovered.contains(file)) {
                        count++;
                    }
                }
                if (count > bestCount) {
                    bestCount = count;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1) {
                break;
            }

            // Add the best test case to the cover
            cover.add(results.getTestCase(bestIdx));

            // Remove covered files from uncovered set
            uncovered.removeAll(caseToFiles.get(bestIdx));
        }

        return cover;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class whose subclasses represent nodes that can generate
 * Python objects from their domains.
 *
 * @param <DomainType> the type of values in the domain
 * @param <ObjType>    the type of Python object generated
 */
public abstract class APyNode<DomainType, ObjType extends APyObj> {

    protected List<DomainType> exDomain;
    protected List<DomainType> ranDomain;
    protected Random rand = new Random();

    public List<DomainType> getExDomain() {
        return this.exDomain;
    }

    public void setExDomain(List<DomainType> exDomain) {
        this.exDomain = exDomain;
    }

    public List<DomainType> getRanDomain() {
        return this.ranDomain;
    }

    public void setRanDomain(List<DomainType> ranDomain) {
        this.ranDomain = ranDomain;
    }

    public abstract APyNode<?, ?> getLeftChild();

    public abstract APyNode<?, ?> getRightChild();

    public abstract Set<ObjType> genExVals();

    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;
import java.util.*;

/**
 * A node for generating PyBoolObj values from a domain of integers (0=false, 1=true).
 */
public class PyBoolNode extends APyNode<Integer, PyBoolObj> {

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            if (val == 0) {
                result.add(new PyBoolObj(false));
            } else if (val == 1) {
                result.add(new PyBoolObj(true));
            }
        }
        return result;
    }

    @Override
    public PyBoolObj genRandVal() {
        Integer val = this.ranDomain.get(this.rand.nextInt(this.ranDomain.size()));
        if (val == 0) {
            return new PyBoolObj(false);
        } else {
            return new PyBoolObj(true);
        }
    }
}

